    }

    /* If we allocated buffer in parse_header, mark it as owned by header stage */
    if (ctx->temp_buffer != NULL && ctx->buffer_size == expected_size) {
        buffer_owned_by_stage = 1;
    }

    /* Calculate payload position and size */
    if (data_size < HEADER_MIN_SIZE + CHECKSUM_SIZE) {
        goto cleanup;
    }

    payload = compressed_data + HEADER_MIN_SIZE;
    payload_size = data_size - HEADER_MIN_SIZE - CHECKSUM_SIZE;

    /* Stage 2: Data decompression */
    if (decompress_payload(payload, payload_size, ctx) != 0) {
        goto cleanup;
    }

    /* If buffer was reallocated or newly allocated in decompress_payload,
       update ownership tracking */
    if (buffer_owned_by_stage == 0 && ctx->temp_buffer != NULL) {
        buffer_owned_by_stage = 2;
    }

    /* Stage 3: Integrity verification */
    if (verify_checksum(compressed_data, data_size, ctx) != 0) {
        goto cleanup;
    }

    /* If we reach here, decompression succeeded */
    result = 0;

cleanup:
    /* Cleanup logic: only free buffer if we own it AND we're failing */
    if (result != 0) {
        /* Only free if we allocated it in one of the stages */
        if (buffer_owned_by_stage > 0) {
            safe_free_buffer(ctx);
        }
    }
    /* On success, buffer ownership is transferred to caller */

    return result;
