/**
 * Parse CMP header and allocate buffer if needed
 * 
 * Returns 0 on success, -1 on failure
 */
static int parse_header(const unsigned char *compressed_data, size_t data_size,
                        struct compression_context *ctx, size_t *expected_size)
{
    size_t decompressed_len;

    /* Check minimum data size */
    if (data_size < HEADER_MIN_SIZE) {
        return -1;
    }

    /* Verify magic number */
    if (compressed_data[0] != CMP_MAGIC_0 || compressed_data[1] != CMP_MAGIC_1) {
        return -1;
    }

    /* Read compression type */
    ctx->compression_type = compressed_data[2];

    /* Read decompressed length */
    memcpy(&decompressed_len, compressed_data + 3, sizeof(size_t));

    /* Security check: prevent integer overflow in allocation */
    if (decompressed_len == 0 || decompressed_len > SIZE_MAX / 2) {
        return -1;
    }

    *expected_size = decompressed_len;

    /* Check if existing buffer is sufficient */
    if (ctx->temp_buffer != NULL && ctx->buffer_size >= decompressed_len) {
        /* Reuse existing buffer */
        ctx->buffer_size = decompressed_len;
    } else {
        /* Allocate new buffer */
        unsigned char *new_buffer = (unsigned char *)malloc(decompressed_len);
        if (new_buffer == NULL) {
            return -1;
        }

        /* Free old buffer if it exists */
        if (ctx->temp_buffer != NULL) {
            free(ctx->temp_buffer);
        }

        ctx->temp_buffer = new_buffer;
        ctx->buffer_size = decompressed_len;
    }

    return 0;
}

/**
 * Decompress payload based on compression type
 * 
 * Returns 0 on success, -1 on failure
 */
static int decompress_payload(const unsigned char *payload, size_t payload_size,
                              struct compression_context *ctx)
{
    if (ctx->temp_buffer == NULL || ctx->buffer_size == 0) {
        return -1;
    }

    switch (ctx->compression_type) {
        case 0: /* Raw/uncompressed */
            if (payload_size != ctx->buffer_size) {
                return -1;
            }
            memcpy(ctx->temp_buffer, payload, payload_size);
            break;

        case 1: /* RLE decompression */
        {
            size_t decompressed_pos = 0;
            size_t payload_pos = 0;

            while (payload_pos < payload_size && decompressed_pos < ctx->buffer_size) {
                if (payload_pos + 2 > payload_size) {
                    return -1;  /* Incomplete RLE pair */
                }

                unsigned char count = payload[payload_pos];
                unsigned char value = payload[payload_pos + 1];

                /* Handle zero count case - this is actually valid for RLE */
                if (count == 0) {
                    /* Skip zero count entries - they don't add any data */
                    payload_pos += 2;
                    continue;
                }

                if (decompressed_pos + count > ctx->buffer_size) {
                    return -1;  /* Would exceed buffer */
                }

                memset(ctx->temp_buffer + decompressed_pos, value, count);
                decompressed_pos += count;
                payload_pos += 2;
            }

            if (decompressed_pos != ctx->buffer_size) {
                return -1;  /* Decompressed size mismatch */
            }

            if (payload_pos != payload_size) {
                return -1;  /* Extra data in payload */
            }
            break;
        }

        default:
            return -1;  /* Unsupported compression type */
    }

    return 0;
}

/**
 * Verify checksum integrity
 * 
 * Returns 0 on success, -1 on failure
 */
static int verify_checksum(const unsigned char *compressed_data, size_t data_size,
                           struct compression_context *ctx)
{
    if (data_size < HEADER_MIN_SIZE + CHECKSUM_SIZE) {
        return -1;
    }

    /* Simple checksum: sum of all bytes in decompressed data modulo 256 */
    unsigned char calculated_checksum = 0;
    for (size_t i = 0; i < ctx->buffer_size; i++) {
        calculated_checksum += ctx->temp_buffer[i];
    }

    unsigned char stored_checksum = compressed_data[data_size - 1];

    if (calculated_checksum != stored_checksum) {
        return -1;
    }

    return 0;
}

/**
 * Safely free buffer and reset context
 * 
 * This function ensures the buffer is only freed once
 */
static void safe_free_buffer(struct compression_context *ctx)
{
    if (ctx->temp_buffer != NULL) {
        free(ctx->temp_buffer);
        ctx->temp_buffer = NULL;
        ctx->buffer_size = 0;
    }
}

